function c(t=new Date){const n=t.getFullYear(),e=String(t.getMonth()+1).padStart(2,"0"),a=String(t.getDate()).padStart(2,"0");return`${n}-${e}-${a}`}function u(t){const n=/^(\d{4})-(\d{2})-(\d{2})$/u.exec(t);if(!n)return!1;const e=Number(n[1]),a=Number(n[2]),r=Number(n[3]),o=new Date(e,a-1,r);return o.getFullYear()===e&&o.getMonth()===a-1&&o.getDate()===r}function s(t){return new Date(`${t}T00:00:00`).toISOString()}function l(t){return new Date(`${t}T23:59:59.999`).toISOString()}export{s as a,l as b,u as i,c as l};
